import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { 
  CreditCard, Users, AlertTriangle, TrendingUp, 
  Calendar, ShoppingCart, DollarSign, Target, CheckCircle2 
} from 'lucide-react';

const Dashboard = () => {
  const [stats, setStats] = useState({
    totalMes: 0,
    totalEmAberto: 0,
    parcelasFuturas: 0,
    maiorParcelaMes: 0,
    totalGeral: 0,
    qtdComprasMes: 0,
    detalhesPorPessoa: {}
  });

  const hoje = new Date();
  const mesAtual = hoje.getMonth();
  const anoAtual = hoje.getFullYear();

  useEffect(() => {
    async function carregarIndicadores() {
      const { data } = await supabase.from('compras').select('*');
      if (!data) return;

      let resumo = {
        totalMes: 0, totalEmAberto: 0, parcelasFuturas: 0,
        maiorParcelaMes: 0, totalGeral: 0, qtdComprasMes: 0,
        detalhesPorPessoa: {}
      };

      data.forEach(item => {
        const valorTotal = parseFloat(item.valor_total);
        const numParcelas = item.num_parcelas || 1;
        const valorParcela = valorTotal / numParcelas;
        const dataCompra = new Date(item.data_compra);
        const responsavel = item.responsavel || 'Indefinido';

        // Inicializa objeto da pessoa se não existir
        if (!resumo.detalhesPorPessoa[responsavel]) {
          resumo.detalhesPorPessoa[responsavel] = {
            totalGeral: 0,
            qtdComprasMes: 0,
            ultimaParcelaDate: new Date(0),
            qtdTotalCompras: 0
          };
        }

        const p = resumo.detalhesPorPessoa[responsavel];
        resumo.totalGeral += valorTotal;
        p.totalGeral += valorTotal;
        p.qtdTotalCompras += 1;

        if (dataCompra.getMonth() === mesAtual && dataCompra.getFullYear() === anoAtual) {
          resumo.qtdComprasMes++;
          p.qtdComprasMes++;
        }

        for (let i = 0; i < numParcelas; i++) {
          const dataParcela = new Date(dataCompra.getFullYear(), dataCompra.getMonth() + i, 1);
          
          if (dataParcela > p.ultimaParcelaDate) p.ultimaParcelaDate = dataParcela;

          if (dataParcela.getMonth() === mesAtual && dataParcela.getFullYear() === anoAtual) {
            resumo.totalMes += valorParcela;
            if (valorParcela > resumo.maiorParcelaMes) resumo.maiorParcelaMes = valorParcela;
          }

          if (dataParcela >= new Date(anoAtual, mesAtual, 1)) {
            resumo.totalEmAberto += valorParcela;
            resumo.parcelasFuturas++;
          }
        }
      });

      setStats(resumo);
    }

    carregarIndicadores();
  }, []);

  const formatMoney = (v) => `R$ ${v.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`;

  return (
    <div className="fade-in" style={{ padding: '20px', backgroundColor: '#f8f9fa' }}>
      
      <h2 style={{ marginBottom: '20px', display: 'flex', alignItems: 'center', gap: '10px' }}>
        <TrendingUp size={24} /> Painel Gerencial
      </h2>
      <div style={gridStyle}>
        <Card title="Valor a pagar no mês" icon={<Calendar size={18} />} value={formatMoney(stats.totalMes)} />
        <Card title="Total em aberto" icon={<DollarSign size={18} />} value={formatMoney(stats.totalEmAberto)} />
        <Card title="Parcelas futuras" icon={<CreditCard size={18} />} value={stats.parcelasFuturas} />
        <Card title="Compras no mês" icon={<ShoppingCart size={18} />} value={stats.qtdComprasMes} />
        <Card title="Maior parcela do mês" icon={<AlertTriangle size={18} />} value={formatMoney(stats.maiorParcelaMes)} />
        <Card title="Total histórico" icon={<TrendingUp size={18} />} value={formatMoney(stats.totalGeral)} highlight />
      </div>

      <h2 style={{ margin: '40px 0 20px 0', display: 'flex', alignItems: 'center', gap: '10px' }}>
        <Users size={24} /> Gestão por Pessoa
      </h2>

      <div style={gridStyle}>
        {Object.entries(stats.detalhesPorPessoa)
          .sort((a, b) => b[1].totalGeral - a[1].totalGeral)
          .map(([nome, dados]) => {
            const percentual = stats.totalGeral ? ((dados.totalGeral / stats.totalGeral) * 100).toFixed(1) : 0;
            const mediaPorCompra = dados.totalGeral / dados.qtdTotalCompras;
            const quitacaoFormatada = dados.ultimaParcelaDate.toLocaleDateString('pt-BR', { month: 'short', year: '2-digit' });

            return (
              <div key={nome} className="card-pessoa" style={personCardStyle}>
                <div style={{ borderBottom: '1px solid #eee', paddingBottom: '15px', marginBottom: '15px' }}>
                  <div style={{ fontSize: '0.75rem', fontWeight: 800, color: 'var(--primary)', textTransform: 'uppercase', letterSpacing: '1px' }}>Responsável</div>
                  <div style={{ fontSize: '1.4rem', fontWeight: 700 }}>{nome}</div>
                </div>

                <div style={{ marginBottom: '20px' }}>
                  <div style={{ fontSize: '0.85rem', opacity: 0.6 }}>Gasto Histórico</div>
                  <div style={{ fontSize: '1.8rem', fontWeight: 800, color: '#2d3436' }}>{formatMoney(dados.totalGeral)}</div>
                  <div style={badgeStyle}>{percentual}% da fatura total</div>
                </div>

                <div style={innerGridStyle}>
                  <MiniStat 
                    label="No Mês" 
                    value={dados.qtdComprasMes} 
                    sub="compras" 
                    icon={<ShoppingCart size={14} />} 
                  />
                  <MiniStat 
                    label="Média/Compra" 
                    value={formatMoney(mediaPorCompra)} 
                    icon={<Target size={14} />} 
                  />
                  <MiniStat 
                    label="Quitação em" 
                    value={quitacaoFormatada} 
                    icon={<CheckCircle2 size={14} />} 
                    highlight 
                  />
                </div>
              </div>
            );
          })}
      </div>
    </div>
  );
};

/* COMPONENTES DE APOIO */
const Card = ({ title, icon, value, highlight }) => (
  <div className="card" style={{
    padding: '20px',
    borderRadius: '12px',
    background: highlight ? 'linear-gradient(135deg, #4361ee, #3a0ca3)' : 'white',
    color: highlight ? 'white' : '#2d3436',
    boxShadow: '0 4px 6px -1px rgba(0,0,0,0.1)',
    transition: 'transform 0.2s'
  }}>
    <div style={{ display: 'flex', alignItems: 'center', gap: '8px', fontSize: '0.7rem', fontWeight: 600, opacity: highlight ? 0.9 : 0.6 }}>
      {icon} {title.toUpperCase()}
    </div>
    <div style={{ fontSize: '1.6rem', fontWeight: 700, marginTop: '12px' }}>{value}</div>
  </div>
);

const MiniStat = ({ label, value, sub, icon, highlight }) => (
  <div style={{ padding: '10px', backgroundColor: highlight ? '#f0f7ff' : '#f8f9fa', borderRadius: '8px' }}>
    <div style={{ fontSize: '0.65rem', opacity: 0.6, display: 'flex', alignItems: 'center', gap: '4px', marginBottom: '4px' }}>
      {icon} {label.toUpperCase()}
    </div>
    <div style={{ fontSize: '0.9rem', fontWeight: 700, color: highlight ? '#4361ee' : '#2d3436' }}>
      {value} <span style={{ fontSize: '0.7rem', fontWeight: 400 }}>{sub}</span>
    </div>
  </div>
);

/* ESTILOS */
